module BCD_counter_4(
   input                clk ,
   input                rst_n,

   output reg [3:0]     Q  
);
    always@(posedge clk or negedge rst_n)begin
        if(!rst_n) Q <= 4'd0;
        else if(Q == 4'd9) Q <= 4'd0;
        else Q <= Q + 4'd1;
    end
  always @(*) begin
    if (1'b0) begin
      if (rst_n) begin
        Q <= 4'd1;
      end
      else if (Q == 4'd8) begin
        Q <= 4'd10;
      end
    end
  end

endmodule

